#include <bits/stdc++.h>
#define ll __int128
using namespace std;

const int N=1e5+10;

int T,n,m,r[N],s[N],b[N],stk[N],top;
long long a[N],p[N];
ll M[N];
set<pair<long long,int>> st;

ll exgcd(ll a,ll b,ll &x,ll &y){
    if(b==0){
        x=1,y=0;
        return a;
    }
    ll z,gcd=exgcd(b,a%b,x,y);
    z=x,x=y,y=z-a/b*y;
    return gcd;
}

int main(){
    scanf("%d",&T);
    while(T--){
        scanf("%d%d",&n,&m);
        for(int i=1;i<=n;i++)
            scanf("%lld",&a[i]);
        for(int i=1;i<=n;i++)
            scanf("%lld",&p[i]);
        for(int i=1;i<=n;i++)
            scanf("%d",&r[i]);
        st.clear();
        for(int i=1;i<=m;i++){
            scanf("%d",&s[i]);
            st.insert(make_pair(s[i],i));
        }
        for(int i=1;i<=n;i++){
            auto it=st.upper_bound(make_pair(a[i]+1,0));
            if(it!=st.begin())
                it--;
            b[i]=(*it).first;
            st.erase(it);
            st.insert(make_pair(r[i],m+i));
            // printf("%d\n",b[i]);
            //printf("%lld %lld %lld\n",b[i],a[i],p[i]);
        }
        ll lcm=1,x=0;
        bool flag=false;
        for(int i=1;i<=n;i++){
            //printf("%d %lld %lld %lld %lld %d\n",b[i],a[i],p[i],(long long)x,(long long)lcm,r[i]);
            ll t,y,gcd=exgcd(b[i]*lcm,p[i],t,y);
            //printf("%lld %lld\n",(long long)(a[i]-b[i]*x),(long long)gcd);
            if((a[i]-b[i]*x)%gcd){
                flag=true;
                break;
            }
            M[i]=p[i]/__gcd(p[i],1ll*b[i]);
            x+=t*((a[i]-b[i]*x)/gcd)%M[i]*lcm;
            gcd=__gcd(lcm,M[i]);
            lcm=lcm*M[i]/gcd;
            x=(x%lcm+lcm)%lcm;
            //printf("%lld\n",(long long)x);
        }
        if(flag){
            puts("-1");
            continue;
        }
        for(int i=1;i<=n;i++)
            if(b[i]*x<a[i])
                x+=((a[i]+b[i]-1)/b[i]-x+lcm-1)/lcm*lcm;
        do{
            stk[++top]=x%10,x/=10;
        }while(x);
        while(top)
            printf("%d",stk[top--]);
        puts("");
    }
    return 0;
}
